    	'{{cite book/new |title=Title |', '}}', '{{cite book |title=Title |', '}}',
		{
			{'others=Name'},
		},
		{nowiki=false, templatestyles=true}
	)
end
function p:test_Others_avmn()
    self:preprocess_equals_preprocess_many(
    	'{{cite AV media/new |title=Title |', '}}', '{{cite AV media |title=Title |', '}}',
		{
			{'others=Name'},
		},
		{nowiki=false, templatestyles=true}
	)
end
